mapper.select:
select
    l.line_id, l.line_code, l.line_name, l.process_type, l.product_type, l.status, l.capacity, l.capacity_unit, l.create_time, l.update_time
     , l.workshop_id, w.workshop_code, w.workshop_name, w.ent_code, e.ent_name
from t_ent_production_line l
left join t_ent_produce_workshop w on w.workshop_id = l.workshop_id
left join t_bas_enterprise e on e.ent_code = w.ent_code



            and w.ent_code = #{entCode}



                AND w.ent_code in

                    #{entCode}





        and l.workshop_id = #{workshopId}


        and l.line_name like concat('%', #{lineName}, '%')


        and l.status = #{status}


order by l.line_id desc

select '${relateProduceFacilityType}' as dataType, r.source_id as lineId, pf.facility_id as id, pf.facility_code as code, pf.facility_name as name, null as type from t_bas_relate r join t_ent_produce_facility pf on pf.facility_id = r.target_id where r.target_type = #{relateProduceFacilityType}
and r.source_id in
#{lineId}
union all
select '${relateGovernanceFacilityType}' as dataType, r.source_id as lineId, cf.facility_id as id, cf.facility_code as code, cf.facility_name as name, null as type from t_bas_relate r join t_ent_poll_control_facility cf on cf.facility_id = r.target_id where r.target_type = #{relateGovernanceFacilityType}
and r.source_id in
#{lineId}
union all
select '${relateOutPutType}' as dataType, r.source_id as lineId, op.out_put_id as id, op.out_put_code as code, op.out_put_name as name, op.out_put_type as type from t_bas_relate r join t_ent_out_put_info op on op.out_put_id = r.target_id where r.target_type = #{relateOutPutType}
and r.source_id in
#{lineId}

mapper.update:
update t_ent_production_line
line_code = #{lineCode}, line_name = #{lineName}, process_type = #{processType}, product_type = #{productType}, status = #{status}, capacity = #{capacity}, capacity_unit = #{capacityUnit},
where line_id = #{lineId}
